"use client"

import { useEffect, useRef } from "react"
import { cn } from "./lib"
import { rgb, type Rgb } from "./palette"
import {
  BAYER4,
  fillOf,
  fnv1a,
  type PixelColor,
  pixelPrefersReducedMotion,
  xorshift32,
} from "./pixel"

// Backing-resolution caps — a placeholder never needs more cells than this.
const MAX_COLS = 960
const MAX_ROWS = 600

export type SkeletonVariant = "block" | "chart"

export type DitherSkeletonProps = {
  /** Fill colour — neutral by default so it reads as chrome, not data. */
  color?: PixelColor
  /** "chart" draws a seeded area silhouette — the placeholder for charts. */
  variant?: SkeletonVariant
  /** CSS px per dither cell — bigger is chunkier. */
  cell?: number
  /** One shimmer sweep (plus dwell), in ms. */
  duration?: number
  /** Overall opacity multiplier. */
  opacity?: number
  /** Seed for the "chart" silhouette — same seed, same shape, so a reloading
   * chart doesn't "pop" between two different placeholder shapes. */
  seed?: string
  className?: string
}

/**
 * Deterministic area silhouette for the "chart" variant: per-column heights in
 * [0.18, 0.92] from two seeded sine waves. Pure and exported for tests.
 */
export function skeletonHeights(
  cols: number,
  seed = "dither-skeleton"
): number[] {
  const rand = xorshift32(fnv1a(seed))
  const f1 = 1.5 + rand() * 1.5
  const f2 = 3 + rand() * 3
  const p1 = rand() * Math.PI * 2
  const p2 = rand() * Math.PI * 2
  return Array.from({ length: cols }, (_, x) => {
    const t = x / Math.max(cols - 1, 1)
    const h =
      0.55 +
      0.28 * Math.sin(p1 + t * f1 * Math.PI) +
      0.12 * Math.sin(p2 + t * f2 * Math.PI)
    return Math.min(0.92, Math.max(0.18, h))
  })
}

/** Shimmer lift for a column: a soft (squared-triangle) band around the wave
 * head — 1 at the head, 0 beyond `span` columns. Pure and exported for tests. */
export function shimmerLift(x: number, waveCol: number, span: number): number {
  const d = Math.abs(x - waveCol) / span
  if (d >= 1) return 0
  const t = 1 - d
  return t * t
}

type SkeletonSpec = {
  fill: Rgb
  heights: number[] | null // null = block variant
  opacity: number
}

/** Paint one shimmer frame. `waveCol` may sit outside [0, cols) — that's the
 * dwell between sweeps (and the whole story under reduced motion). */
function paintSkeleton(
  ctx: CanvasRenderingContext2D,
  cols: number,
  rows: number,
  { fill, heights, opacity }: SkeletonSpec,
  waveCol: number
): void {
  ctx.clearRect(0, 0, cols, rows)
  const span = Math.max(6, cols * 0.25)
  for (let x = 0; x < cols; x++) {
    const lift = shimmerLift(x, waveCol, span)
    // The silhouette column starts lower for taller heights (area chart look).
    const yStart = heights ? Math.round(rows * (1 - heights[x])) : 0
    for (let y = yStart; y < rows; y++) {
      const density = 0.16 + 0.3 * lift
      const lit = density > BAYER4[y & 3][x & 3]
      const alpha = (lit ? 0.3 + 0.7 * density : 0.1 * density) * opacity
      if (alpha <= 0.004) continue
      ctx.fillStyle = rgb(fill, 1, alpha)
      ctx.fillRect(x, y, 1, 1)
    }
  }
}

/**
 * Dithered loading placeholder — the ordered-dither texture with a slow
 * shimmer band sweeping through it. Size it like any skeleton (className);
 * `variant="chart"` shapes it as a seeded area silhouette so chart slots
 * load "in character". Decorative: always aria-hidden — keep a text
 * alternative (or aria-busy) on the host region.
 */
export function DitherSkeleton({
  color = "grey",
  variant = "block",
  cell = 3,
  duration = 1800,
  opacity = 0.75,
  seed = "dither-skeleton",
  className,
}: DitherSkeletonProps) {
  const wrapRef = useRef<HTMLDivElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    const wrap = wrapRef.current
    const canvas = canvasRef.current
    const ctx = canvas?.getContext("2d")
    if (!wrap || !canvas || !ctx) return

    const reduce = pixelPrefersReducedMotion()
    const spec: SkeletonSpec = { fill: fillOf(color), heights: null, opacity }
    let cols = 0
    let rows = 0
    let raf = 0
    const start = performance.now()

    const frame = (now: number) => {
      // 0–1 sweeps, then a dwell (the extra 0.4) with the band off-canvas.
      const cycle = (((now - start) % duration) / duration) * 1.4
      const span = Math.max(6, cols * 0.25)
      const waveCol = cycle * (cols + span * 2) - span
      paintSkeleton(ctx, cols, rows, spec, waveCol)
      raf = requestAnimationFrame(frame)
    }

    const resize = () => {
      const box = wrap.getBoundingClientRect()
      cols = Math.min(MAX_COLS, Math.max(4, Math.round(box.width / cell)))
      rows = Math.min(MAX_ROWS, Math.max(4, Math.round(box.height / cell)))
      canvas.width = cols
      canvas.height = rows
      spec.heights = variant === "chart" ? skeletonHeights(cols, seed) : null
      if (reduce) paintSkeleton(ctx, cols, rows, spec, Number.NEGATIVE_INFINITY)
    }
    resize()

    if (!reduce) raf = requestAnimationFrame(frame)
    const ro =
      typeof ResizeObserver !== "undefined" ? new ResizeObserver(resize) : null
    ro?.observe(wrap)

    return () => {
      if (raf) cancelAnimationFrame(raf)
      ro?.disconnect()
    }
  }, [color, variant, cell, duration, opacity, seed])

  return (
    <div
      ref={wrapRef}
      aria-hidden
      className={cn("relative overflow-hidden", className)}
    >
      <canvas
        ref={canvasRef}
        className="absolute inset-0 h-full w-full"
        style={{ imageRendering: "pixelated" }}
      />
    </div>
  )
}

// Standalone pixel primitives for the non-chart Dither Kit pieces (avatar,
// gradient). Deliberately free of the chart engine so those items install
// without `core` — only palette.ts is shared. The Bayer matrix and bloom
// presets mirror dither-paint.ts so everything reads as one texture.

import { type DitherColor, PALETTE, type Rgb } from "./palette"

// 4×4 ordered (Bayer) matrix, normalized to 0–1 thresholds — the same matrix
// the charts dither with.
export const BAYER4 = [
  [0, 8, 2, 10],
  [12, 4, 14, 6],
  [3, 11, 1, 9],
  [15, 7, 13, 5],
].map((row) => row.map((v) => (v + 0.5) / 16))

export const clamp01 = (t: number) => (t < 0 ? 0 : t > 1 ? 1 : t)

/** 32-bit FNV-1a hash — turns any string seed into a stable uint32. */
export function fnv1a(str: string): number {
  let h = 0x811c9dc5
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i)
    h = Math.imul(h, 0x01000193)
  }
  return h >>> 0
}

/** Tiny deterministic PRNG (xorshift32) — returns floats in [0, 1). */
export function xorshift32(seed: number): () => number {
  let s = seed || 0x9e3779b9
  return () => {
    s ^= s << 13
    s >>>= 0
    s ^= s >>> 17
    s ^= s << 5
    s >>>= 0
    return s / 0x100000000
  }
}

/** A named palette colour or a raw hue (0–360). */
export type PixelColor = DitherColor | number

/** Hue (0–360) → an rgb fill tuned to sit alongside the chart palette. */
export function hueFill(hue: number): Rgb {
  const h = ((hue % 360) + 360) % 360
  const s = 0.85
  const l = 0.58
  const c = (1 - Math.abs(2 * l - 1)) * s
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = l - c / 2
  const [r, g, b] =
    h < 60
      ? [c, x, 0]
      : h < 120
        ? [x, c, 0]
        : h < 180
          ? [0, c, x]
          : h < 240
            ? [0, x, c]
            : h < 300
              ? [x, 0, c]
              : [c, 0, x]
  return [
    Math.round((r + m) * 255),
    Math.round((g + m) * 255),
    Math.round((b + m) * 255),
  ]
}

/** Resolve a {@link PixelColor} to its rgb fill. */
export function fillOf(color: PixelColor): Rgb {
  return typeof color === "number" ? hueFill(color) : PALETTE[color].fill
}

// Bloom — same recipe as the charts: a blurred copy of the crisp canvas,
// composited additively so the glow stays in the dither's own colour.
export type PixelBloom = "off" | "low" | "high" | "aura"

const BLOOM_PRESET: Record<
  Exclude<PixelBloom, "off">,
  { blur: number; brightness: number; opacity: number; saturate: number }
> = {
  low: { blur: 3, brightness: 1.35, opacity: 0.7, saturate: 1.4 },
  high: { blur: 5, brightness: 1.5, opacity: 0.78, saturate: 1.5 },
  aura: { blur: 15, brightness: 2.9, opacity: 0.1, saturate: 3 },
}

export type PixelBloomStyle = {
  filter: string
  opacity: number
  mixBlendMode: "plus-lighter"
  imageRendering: "auto"
}

/** Style for the bloom layer canvas. null when off. */
export function pixelBloomStyle(bloom: PixelBloom): PixelBloomStyle | null {
  if (bloom === "off") return null
  const cfg = BLOOM_PRESET[bloom]
  return {
    filter: `blur(${cfg.blur}px) brightness(${cfg.brightness}) saturate(${cfg.saturate})`,
    opacity: cfg.opacity,
    mixBlendMode: "plus-lighter",
    imageRendering: "auto",
  }
}

/** Whether the OS asks for reduced motion (skip entrances). */
export function pixelPrefersReducedMotion(): boolean {
  return (
    window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches ?? false
  )
}

// Shared seed palette for the dither chart family. Mirrors the seeds in
// `dither-chart.tsx` so a series rendered through the composable engine reads
// with the exact same fill / line / star hues as the legacy sparkline.

export type Rgb = [number, number, number]

export type DitherColor =
  | "green"
  | "blue"
  | "purple"
  | "pink"
  | "orange"
  | "red"
  | "grey"

export type Seed = { fill: Rgb; line: Rgb; star: Rgb }

// Each seed: the area-fill hue, the bright series line, and the star sparkle.
export const PALETTE: Record<DitherColor, Seed> = {
  green: { fill: [40, 210, 110], line: [150, 255, 180], star: [200, 255, 220] },
  blue: { fill: [53, 143, 243], line: [150, 200, 255], star: [205, 228, 255] },
  purple: {
    fill: [150, 110, 255],
    line: [200, 175, 255],
    star: [225, 210, 255],
  },
  pink: { fill: [240, 90, 190], line: [255, 170, 220], star: [255, 205, 235] },
  orange: {
    fill: [255, 150, 50],
    line: [255, 195, 130],
    star: [255, 220, 175],
  },
  red: { fill: [240, 70, 70], line: [255, 150, 140], star: [255, 195, 185] },
  // No-data: a muted grey so empty metrics read as "nothing here".
  grey: { fill: [92, 92, 100], line: [140, 140, 150], star: [165, 165, 175] },
}

export const rgb = ([r, g, b]: Rgb, k = 1, a = 1) =>
  `rgba(${Math.round(r * k)},${Math.round(g * k)},${Math.round(b * k)},${a})`

export const seedOfColor = (color: DitherColor): Seed => PALETTE[color]

export const isDitherColor = (value: unknown): value is DitherColor =>
  typeof value === "string" && value in PALETTE

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

/** Tailwind-aware className combiner — local copy so the chart pack is
 * self-contained and portable as a registry. */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
